 1→import tableTemplate from './tableTemplate';
 2→import cabinetTemplate from './cabinetTemplate';
 3→import deskTemplate from './deskTemplate';
 4→import shelfTemplate from './shelfTemplate';
 5→
 6→const templates = [tableTemplate, cabinetTemplate, deskTemplate, shelfTemplate];
 7→const templateMap = new Map(templates.map((t) => [t.type, t]));
 8→
 9→export const templateList = templates;
10→
11→export function getTemplate(type) {
12→  return templateMap.get(type) || null;
13→}
14→
15→export function getDefaultParams(type) {
16→  const template = getTemplate(type);
17→  if (!template) return {};
18→  const defaults = {};
19→  for (const param of template.parameters) {
20→    defaults[param.key] = param.default;
21→  }
22→  return defaults;
23→}
