 1→import { createPanel, createLeg } from '../partModels';
 2→
 3→const tableTemplate = {
 4→  type: 'table',
 5→  label: 'Table',
 6→  description: 'Tabletop with four legs at corners',
 7→  parameters: [
 8→    { key: 'width', label: 'Width', type: 'number', default: 1200, min: 200, max: 5000, step: 10, suffix: 'mm' },
 9→    { key: 'depth', label: 'Depth', type: 'number', default: 600, min: 200, max: 3000, step: 10, suffix: 'mm' },
10→    { key: 'height', label: 'Height', type: 'number', default: 750, min: 200, max: 2000, step: 10, suffix: 'mm' },
11→    { key: 'topThickness', label: 'Top Thickness', type: 'number', default: 18, min: 6, max: 80, step: 1, suffix: 'mm' },
12→    { key: 'legWidth', label: 'Leg Width', type: 'number', default: 40, min: 10, max: 200, step: 5, suffix: 'mm' },
13→    { key: 'legDepth', label: 'Leg Depth', type: 'number', default: 40, min: 10, max: 200, step: 5, suffix: 'mm' },
14→    { key: 'legInset', label: 'Leg Inset', type: 'number', default: 30, min: 0, max: 200, step: 5, suffix: 'mm' },
15→  ],
16→  generate(params) {
17→    const { width, depth, height, topThickness, legWidth, legDepth, legInset } = params;
18→    const legHeight = height - topThickness;
19→
20→    const tabletop = createPanel({
21→      name: 'Tabletop',
22→      width,
23→      depth,
24→      thickness: topThickness,
25→      material: 'plywood',
26→      position: { x: 0, y: 0, z: legHeight },
27→    });
28→
29→    const legTL = createLeg({
30→      name: 'Leg TL',
31→      width: legWidth, depth: legDepth, height: legHeight,
32→      position: { x: legInset, y: legInset, z: 0 },
33→    });
34→
35→    const legTR = createLeg({
36→      name: 'Leg TR',
37→      width: legWidth, depth: legDepth, height: legHeight,
38→      position: { x: width - legInset - legWidth, y: legInset, z: 0 },
39→    });
40→
41→    const legBL = createLeg({
42→      name: 'Leg BL',
43→      width: legWidth, depth: legDepth, height: legHeight,
44→      position: { x: legInset, y: depth - legInset - legDepth, z: 0 },
45→    });
46→
47→    const legBR = createLeg({
48→      name: 'Leg BR',
49→      width: legWidth, depth: legDepth, height: legHeight,
50→      position: { x: width - legInset - legWidth, y: depth - legInset - legDepth, z: 0 },
51→    });
52→
53→    return {
54→      parts: [tabletop, legTL, legTR, legBL, legBR],
55→      name: `Table ${width}×${depth}`,
56→    };
57→  },
58→};
59→
60→export default tableTemplate;
