  1→import { createPanel } from '../partModels';
  2→
  3→const cabinetTemplate = {
  4→  type: 'cabinet',
  5→  label: 'Cabinet',
  6→  description: 'Box with sides, shelves, optional doors and back',
  7→  parameters: [
  8→    { key: 'width', label: 'Width', type: 'number', default: 600, min: 200, max: 3000, step: 10, suffix: 'mm' },
  9→    { key: 'depth', label: 'Depth', type: 'number', default: 400, min: 150, max: 1500, step: 10, suffix: 'mm' },
 10→    { key: 'height', label: 'Height', type: 'number', default: 800, min: 200, max: 3000, step: 10, suffix: 'mm' },
 11→    { key: 'panelThickness', label: 'Panel Thickness', type: 'number', default: 18, min: 6, max: 50, step: 1, suffix: 'mm' },
 12→    { key: 'shelfCount', label: 'Shelves', type: 'integer', default: 2, min: 0, max: 10, step: 1, suffix: '' },
 13→    { key: 'hasDoors', label: 'Doors', type: 'boolean', default: false },
 14→    { key: 'hasBack', label: 'Back Panel', type: 'boolean', default: true },
 15→  ],
 16→  generate(params) {
 17→    const { width, depth, height, panelThickness, shelfCount, hasDoors, hasBack } = params;
 18→    const innerWidth = width - 2 * panelThickness;
 19→    const innerHeight = height - 2 * panelThickness;
 20→    const parts = [];
 21→
 22→    // Left side panel (vertical)
 23→    parts.push(createPanel({
 24→      name: 'Left Side',
 25→      width: panelThickness,
 26→      depth,
 27→      thickness: innerHeight,
 28→      material: 'plywood',
 29→      position: { x: 0, y: 0, z: panelThickness },
 30→    }));
 31→
 32→    // Right side panel (vertical)
 33→    parts.push(createPanel({
 34→      name: 'Right Side',
 35→      width: panelThickness,
 36→      depth,
 37→      thickness: innerHeight,
 38→      material: 'plywood',
 39→      position: { x: width - panelThickness, y: 0, z: panelThickness },
 40→    }));
 41→
 42→    // Bottom panel
 43→    parts.push(createPanel({
 44→      name: 'Bottom',
 45→      width: innerWidth,
 46→      depth,
 47→      thickness: panelThickness,
 48→      material: 'plywood',
 49→      position: { x: panelThickness, y: 0, z: 0 },
 50→    }));
 51→
 52→    // Top panel
 53→    parts.push(createPanel({
 54→      name: 'Top',
 55→      width: innerWidth,
 56→      depth,
 57→      thickness: panelThickness,
 58→      material: 'plywood',
 59→      position: { x: panelThickness, y: 0, z: height - panelThickness },
 60→    }));
 61→
 62→    // Shelves
 63→    if (shelfCount > 0) {
 64→      const spacing = innerHeight / (shelfCount + 1);
 65→      for (let i = 1; i <= shelfCount; i++) {
 66→        const z = panelThickness + spacing * i - panelThickness / 2;
 67→        parts.push(createPanel({
 68→          name: `Shelf ${i}`,
 69→          width: innerWidth,
 70→          depth,
 71→          thickness: panelThickness,
 72→          material: 'plywood',
 73→          position: { x: panelThickness, y: 0, z },
 74→        }));
 75→      }
 76→    }
 77→
 78→    // Optional back panel
 79→    if (hasBack) {
 80→      parts.push(createPanel({
 81→        name: 'Back',
 82→        width,
 83→        depth: panelThickness,
 84→        thickness: height,
 85→        material: 'plywood',
 86→        position: { x: 0, y: depth - panelThickness, z: 0 },
 87→        fill: 'rgba(120, 120, 120, 0.06)',
 88→      }));
 89→    }
 90→
 91→    // Optional doors
 92→    if (hasDoors) {
 93→      const doorWidth = innerWidth / 2;
 94→      parts.push(createPanel({
 95→        name: 'Left Door',
 96→        width: doorWidth,
 97→        depth: panelThickness,
 98→        thickness: innerHeight,
 99→        material: 'plywood',
100→        position: { x: panelThickness, y: 0, z: panelThickness },
101→        fill: 'rgba(184, 134, 11, 0.1)',
102→      }));
103→      parts.push(createPanel({
104→        name: 'Right Door',
105→        width: doorWidth,
106→        depth: panelThickness,
107→        thickness: innerHeight,
108→        material: 'plywood',
109→        position: { x: panelThickness + doorWidth, y: 0, z: panelThickness },
110→        fill: 'rgba(184, 134, 11, 0.1)',
111→      }));
112→    }
113→
114→    return {
115→      parts,
116→      name: `Cabinet ${width}×${depth}×${height}`,
117→    };
118→  },
119→};
120→
121→export default cabinetTemplate;
