 1→import { createPanel } from '../partModels';
 2→
 3→const shelfTemplate = {
 4→  type: 'shelf',
 5→  label: 'Shelf Unit',
 6→  description: 'Tall shelving with adjustable shelf count',
 7→  parameters: [
 8→    { key: 'width', label: 'Width', type: 'number', default: 800, min: 200, max: 3000, step: 10, suffix: 'mm' },
 9→    { key: 'depth', label: 'Depth', type: 'number', default: 300, min: 100, max: 1000, step: 10, suffix: 'mm' },
10→    { key: 'height', label: 'Height', type: 'number', default: 1800, min: 400, max: 3000, step: 10, suffix: 'mm' },
11→    { key: 'sideThickness', label: 'Side Thickness', type: 'number', default: 18, min: 6, max: 50, step: 1, suffix: 'mm' },
12→    { key: 'shelfThickness', label: 'Shelf Thickness', type: 'number', default: 18, min: 6, max: 50, step: 1, suffix: 'mm' },
13→    { key: 'shelfCount', label: 'Shelves', type: 'integer', default: 4, min: 1, max: 15, step: 1, suffix: '' },
14→    { key: 'hasBack', label: 'Back Panel', type: 'boolean', default: true },
15→  ],
16→  generate(params) {
17→    const { width, depth, height, sideThickness, shelfThickness, shelfCount, hasBack } = params;
18→    const innerWidth = width - 2 * sideThickness;
19→    const parts = [];
20→
21→    // Left side
22→    parts.push(createPanel({
23→      name: 'Left Side',
24→      width: sideThickness,
25→      depth,
26→      thickness: height,
27→      material: 'plywood',
28→      position: { x: 0, y: 0, z: 0 },
29→    }));
30→
31→    // Right side
32→    parts.push(createPanel({
33→      name: 'Right Side',
34→      width: sideThickness,
35→      depth,
36→      thickness: height,
37→      material: 'plywood',
38→      position: { x: width - sideThickness, y: 0, z: 0 },
39→    }));
40→
41→    // Shelves (evenly spaced including top and bottom)
42→    const totalShelves = shelfCount + 2; // +2 for top and bottom
43→    const spacing = height / (totalShelves - 1);
44→
45→    for (let i = 0; i < totalShelves; i++) {
46→      const z = spacing * i;
47→      const isTopOrBottom = i === 0 || i === totalShelves - 1;
48→      parts.push(createPanel({
49→        name: isTopOrBottom ? (i === 0 ? 'Bottom' : 'Top') : `Shelf ${i}`,
50→        width: innerWidth,
51→        depth,
52→        thickness: shelfThickness,
53→        material: 'plywood',
54→        position: { x: sideThickness, y: 0, z },
55→      }));
56→    }
57→
58→    // Optional back panel
59→    if (hasBack) {
60→      parts.push(createPanel({
61→        name: 'Back',
62→        width,
63→        depth: Math.max(6, sideThickness / 2),
64→        thickness: height,
65→        material: 'plywood',
66→        position: { x: 0, y: depth - Math.max(6, sideThickness / 2), z: 0 },
67→        fill: 'rgba(120, 120, 120, 0.06)',
68→      }));
69→    }
70→
71→    return {
72→      parts,
73→      name: `Shelf ${width}×${height}`,
74→    };
75→  },
76→};
77→
78→export default shelfTemplate;
