 42→export default function TemplateDialog({ onClose, onGenerate }) {
 43→  const [selectedType, setSelectedType] = useState(null);
 44→  const [params, setParams] = useState({});
 45→
 46→  const handleSelectTemplate = (type) => {
 47→    setSelectedType(type);
 48→    setParams(getDefaultParams(type));
 49→  };
 50→
 51→  const handleParamChange = (key, value) => {
 52→    setParams((prev) => ({ ...prev, [key]: value }));
 53→  };
 54→
 55→  const handleCreate = () => {
 56→    onGenerate(selectedType, params);
 57→    onClose();
 58→  };
 59→
 60→  const selectedTemplate = selectedType
 61→    ? templateList.find((t) => t.type === selectedType)
 62→    : null;
 63→
 64→  return (
 65→    <Modal title="Create from Template" onClose={onClose}>
 66→      {!selectedTemplate ? (
 67→        <div className={styles.grid}>
 68→          {templateList.map((tmpl) => (
 69→            <button
 70→              key={tmpl.type}
 71→              className={styles.card}
 72→              onClick={() => handleSelectTemplate(tmpl.type)}
 73→            >
 74→              {TEMPLATE_ICONS[tmpl.type] || null}
 75→              <span className={styles.cardLabel}>{tmpl.label}</span>
 76→              <span className={styles.cardDesc}>{tmpl.description}</span>
 77→            </button>
 78→          ))}
 79→        </div>
 80→      ) : (
 81→        <div className={styles.paramView}>
 82→          <div className={styles.paramHeader}>
 83→            <button className={styles.backBtn} onClick={() => setSelectedType(null)}>
 84→              <svg viewBox="0 0 16 16" width="14" height="14">
 85→                <path d="M10 3L5 8l5 5" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round" />
 86→              </svg>
 87→              Back
 88→            </button>
 89→            <span className={styles.paramTitle}>{selectedTemplate.label}</span>
 90→          </div>
 91→
 92→          <TemplateParamsForm
 93→            parameters={selectedTemplate.parameters}
 94→            values={params}
 95→            onChange={handleParamChange}
 96→          />
 97→
 98→          <button className={styles.createBtn} onClick={handleCreate}>
 99→            Create {selectedTemplate.label}
100→          </button>
101→        </div>
102→      )}
103→    </Modal>
104→  );
105→}
