531→export default function SketchPropertiesPanel() {
532→  const { getPart, dispatch, project } = useSketch();
533→  const { selectedId, selectedType, workspaceMode, activeSheetId, dispatch: editorDispatch } = useSketchEditor();
534→
535→  const isSheetMode = workspaceMode === 'sheet';
536→  const activeSheet = isSheetMode
537→    ? (project.sheets || []).find((s) => s.id === activeSheetId)
538→    : null;
539→
540→  // Sheet mode properties
541→  if (isSheetMode) {
542→    if (selectedType === 'sheetViewport' && selectedId && activeSheet) {
543→      const viewport = (activeSheet.viewports || []).find((vp) => vp.id === selectedId);
544→      if (viewport) {
545→        return (
546→          <div className={styles.panel}>
547→            <div className={styles.header}>Viewport Properties</div>
548→            <div className={styles.content}>
549→              <SheetViewportProperties
550→                viewport={viewport}
551→                sheet={activeSheet}
552→                project={project}
553→                dispatch={dispatch}
554→              />
555→            </div>
556→          </div>
557→        );
558→      }
559→    }
560→
561→    if (activeSheet) {
562→      const handleGenerateAssemblySheet = (assemblyId) => {
563→        const sheet = generateAssemblySheet(project, assemblyId);
564→        dispatch({ type: 'SKETCH_SHEET_ADD', sheet });
565→        editorDispatch({ type: 'SET_ACTIVE_SHEET', sheetId: sheet.id });
566→      };
567→
568→      const handleExportPdf = async () => {
569→        try {
570→          await exportActiveSheetAsPdf(activeSheet.title || 'sketch-sheet', activeSheet.paperSize);
571→        } catch (err) {
572→          console.error('PDF export failed:', err);
573→        }
574→      };
575→
576→      const handleExportPng = async () => {
577→        try {
578→          await exportActiveSheetAsPng(activeSheet.title || 'sketch-sheet');
579→        } catch (err) {
580→          console.error('PNG export failed:', err);
581→        }
582→      };
583→
584→      return (
585→        <div className={styles.panel}>
586→          <div className={styles.header}>Sheet Properties</div>
587→          <div className={styles.content}>
588→            <SheetProperties sheet={activeSheet} project={project} dispatch={dispatch} />
589→
590→            <div className={styles.fieldGroup}>
591→              <span className={styles.groupTitle}>Actions</span>
592→              {(project.assemblies || []).map((asm) => (
593→                <button
594→                  key={asm.id}
595→                  className={styles.duplicateBtn}
596→                  onClick={() => handleGenerateAssemblySheet(asm.id)}
597→                >
598→                  Generate Sheet: {asm.name}
599→                </button>
600→              ))}
601→              <button className={styles.duplicateBtn} onClick={handleExportPdf}>
602→                Export PDF
603→              </button>
604→              <button className={styles.duplicateBtn} onClick={handleExportPng}>
605→                Export PNG
606→              </button>
607→            </div>
608→          </div>
609→        </div>
610→      );
611→    }
612→
613→    return (
614→      <div className={styles.panel}>
615→        <div className={styles.header}>Properties</div>
616→        <div className={styles.empty}>No sheet selected</div>
617→      </div>
618→    );
619→  }
620→
621→  // Model mode: assembly selection
622→  if (selectedType === 'assembly' && selectedId) {
623→    const asm = project.assemblies.find((a) => a.id === selectedId);
624→    if (asm) {
625→      return (
626→        <AssemblyProperties key={asm.id} assembly={asm} project={project} dispatch={dispatch} />
627→      );
628→    }
629→  }
630→
631→  // Model mode properties
632→  const part = selectedId ? getPart(selectedId) : null;
633→
634→  if (!part) {
635→    return (
636→      <div className={styles.panel}>
637→        <div className={styles.header}>Properties</div>
638→        <div className={styles.empty}>Select a part to view its properties</div>
639→      </div>
640→    );
641→  }
642→
643→  const handleUpdate = (changes) => {
644→    dispatch({ type: 'PART_UPDATE', part: { id: part.id, ...changes } });
645→  };
646→
647→  const handlePositionUpdate = (posChanges) => {
648→    dispatch({ type: 'PART_UPDATE', part: { id: part.id, position: { ...part.position, ...posChanges } } });
649→  };
650→
651→  const handleDuplicate = () => {
652→    dispatch({ type: 'PART_CLONE', partId: part.id });
653→  };
654→
655→  const isDimension = part.type === 'dimension';
656→  const FieldsComponent = isDimension ? null : partFieldComponents[part.type];
657→
658→  // Find assembly this part belongs to
659→  const assembly = part.assemblyId
660→    ? project.assemblies.find((a) => a.id === part.assemblyId)
661→    : null;
662→
