309→export default function SketchWorkspace({ initialProject }) {
310→  return (
311→    <div className="editorRoot">
312→      <SketchProvider initialProject={initialProject}>
313→        <SketchEditorProvider>
314→          <SketchInner />
315→        </SketchEditorProvider>
316→      </SketchProvider>
317→    </div>
318→  );
319→}
